def binary_search(sorted_list: list, target: int) -> int:
    """在有序列表中执行二分查找，返回目标值的索引，未找到则返回-1。

    Args:
        sorted_list: 已排序的列表（升序）
        target: 要查找的目标值

    Returns:
        int: 目标值在列表中的索引，未找到返回-1
    """
    if not isinstance(sorted_list, list):
        return -1

    left, right = 0, len(sorted_list) - 1

    while left <= right:
        mid = (left + right) // 2
        if sorted_list[mid] == target:
            return mid
        elif sorted_list[mid] < target:
            left = mid + 1
        else:
            right = mid - 1

    return -1

def binary_search(sorted_list, target) -> dict:
    """
    在有序列表中执行二分查找以定位目标值。

    参数:
    sorted_list (list): 一个已排序的列表。
    target: 要查找的目标值。

    返回:
    dict: 包含索引或错误信息的字典。成功时返回 {"index": index}，其中 index 是目标值的索引，如果未找到则为 -1。失败时返回 {"error": "错误信息"}。
    """
    try:
        left = 0
        right = len(sorted_list) - 1

        while left <= right:
            mid = (left + right) // 2
            if sorted_list[mid] == target:
                return {"index": mid}
            elif sorted_list[mid] < target:
                left = mid + 1
            else:
                right = mid - 1

        return {"index": -1}
    except Exception as e:
        return {"error": str(e)}

def cached_fibonacci(n) -> dict:
    # 检查输入是否为整数
    if not isinstance(n, int):
        return {'error': 'n must be an integer'}
    # 检查输入是否为非负整数
    if n < 0:
        return {'error': 'n must be a non-negative integer'}
    # 使用缓存字典存储已计算的斐波那契数
    cache = {0: 0, 1: 1}
    # 递归函数，使用缓存
    def fib(k):
        if k in cache:
            return cache[k]
        cache[k] = fib(k-1) + fib(k-2)
        return cache[k]
    # 计算第n项
    result = fib(n)
    return {'result': result}

