        total_sum = 0
        valid_rows = 0

        for row in rows:
            # 每行必须是列表且至少有两个元素
            if not isinstance(row, list) or len(row) < 2:
                return {'error': 'Invalid row format: each row must be a list with at least two elements'}

            value_str = row[1]

            # 尝试将第二列的值转换为数字
            try:
                value = float(value_str)
                total_sum += value
                valid_rows += 1
            except (ValueError, TypeError):
                # 如果转换失败，根据测试用例，整个操作应返回错误
                return {'error': 'Invalid numeric value in second column'}

        return {'sum': total_sum, 'rows': valid_rows}

    except json.JSONDecodeError:
        return {'error': 'Invalid JSON format'}
    except Exception as e:
        return {'error': f'Unexpected error: {str(e)}'}

