def fibonacci_with_cache(n) -> dict:
    """计算斐波那契数列，支持缓存以提高重复计算效率。

    Args:
        n: 非负整数，表示要计算的斐波那契数列的索引。

    Returns:
        dict: 包含以下键的字典：
            - n: 输入的n值
            - result: 斐波那契数列第n项的值
            - cache_hit: 是否命中缓存（布尔值）
        如果输入无效（非整数或负数），返回包含error字段的字典。
    """
    # 检查输入是否为整数
    if not isinstance(n, int):
        return {"error": "n must be an integer"}
    # 检查输入是否为非负整数
    if n < 0:
        return {"error": "n must be a non-negative integer"}

    # 使用模块级缓存（静态变量）
    if not hasattr(fibonacci_with_cache, "cache"):
        fibonacci_with_cache.cache = {0: 0, 1: 1}

    cache = fibonacci_with_cache.cache
    cache_hit = n in cache

    if cache_hit:
        result = cache[n]
    else:
        # 计算斐波那契数列并缓存结果
        a, b = 0, 1
        for i in range(2, n + 1):
            a, b = b, a + b
            # 缓存中间结果以提高后续查询效率
            if i not in cache:
                cache[i] = b
        result = b

    return {"n": n, "result": result, "cache_hit": cache_hit}

def fibonacci_with_cache(n):
    """计算斐波那契数列的第n项，支持缓存以提高效率。

    参数:
        n (int): 非负整数，表示斐波那契数列的索引。

    返回:
        dict: 成功时返回 {"fibonacci_number": value}，失败时返回 {"error": "error message"}。
    """
    if not isinstance(n, int):
        return {"error": "n must be an integer"}

    if n < 0:
        return {"error": "n must be non-negative"}

    if not hasattr(fibonacci_with_cache, "cache"):
        fibonacci_with_cache.cache = {}
    cache = fibonacci_with_cache.cache

    if n in cache:
        return {"fibonacci_number": cache[n]}

    def fib(k):
        if k in cache:
            return cache[k]
        if k <= 1:
            cache[k] = k
            return k
        cache[k] = fib(k-1) + fib(k-2)
        return cache[k]

    result = fib(n)
    return {"fibonacci_number": result}

def filter_sort_strings(strings) -> dict:
    '''
    从输入的字符串列表中筛选出长度大于3的字符串，并按字母顺序排序。

    参数:
        strings (list): 字符串列表。

    返回:
        dict: 成功时返回 {'result': sorted_list}，失败时返回 {'error': error_message}。
    '''
    # 检查输入是否为列表
    if not isinstance(strings, list):
        return {'error': 'Input must be a list'}

    # 检查所有元素是否为字符串
    for item in strings:
        if not isinstance(item, str):
            return {'error': 'All elements must be strings'}

    # 筛选长度大于3的字符串
    filtered = [s for s in strings if len(s) > 3]

    # 按字母顺序排序
    sorted_list = sorted(filtered)

    # 返回结果
    return {'result': sorted_list}

def flatten_nested_list(nested_list) -> dict:
    """展平任意深度的嵌套列表，支持列表和元组，保留字典和其它非列表元素作为原子值。

    参数:
        nested_list: 要展平的嵌套列表或元组。

    返回:
        dict: 成功时包含 'result' 键，值为展平后的列表；失败时包含 'error' 键，值为错误信息。
    """
    if not isinstance(nested_list, (list, tuple)):
        return {"error": "Input must be a list or tuple"}

    def flatten(item):
        if isinstance(item, (list, tuple)):
            result = []
            for sub_item in item:
                result.extend(flatten(sub_item))
            return result
        else:
            return [item]

    flattened = flatten(nested_list)
    return {"result": flattened}

