def merge_dicts_with_list_values(dict1, dict2) -> dict:
    if not isinstance(dict1, dict) or not isinstance(dict2, dict):
        return {'error': 'Both inputs must be dictionaries'}
    result = {}
    for key, value in dict1.items():
        result[key] = value
    for key, value in dict2.items():
        if key in result:
            existing = result[key]
            if isinstance(existing, list):
                result[key] = existing + [value]
            else:
                result[key] = [existing, value]
        else:
            result[key] = value
    return result

def merge_dicts_with_list_values(dict1, dict2) -> dict:
    """合并两个字典，当键冲突时将值合并为列表。

    参数:
        dict1 (dict): 第一个字典
        dict2 (dict): 第二个字典

    返回:
        dict: 合并后的字典，包含键 'merged_dict'，其值为合并结果；
              如果输入无效，返回包含 'error' 字段的字典。
    """
    # 验证输入是否为字典
    if not isinstance(dict1, dict) or not isinstance(dict2, dict):
        return {"error": "Both inputs must be dictionaries"}

    # 初始化结果字典
    merged = {}

    # 处理 dict1 的所有键
    for key, value in dict1.items():
        merged[key] = value

    # 处理 dict2 的所有键，处理冲突
    for key, value in dict2.items():
        if key in merged:
            # 如果键已存在，将现有值和新值合并为列表
            existing = merged[key]
            if isinstance(existing, list):
                # 如果已经是列表，直接追加
                existing.append(value)
            else:
                # 否则，创建新列表包含两个值
                merged[key] = [existing, value]
        else:
            # 键不存在，直接添加
            merged[key] = value

    # 按规约要求返回包含 'merged_dict' 键的字典
    return {"merged_dict": merged}

