def reverse_string(input_string) -> dict:
    """将输入的字符串进行反转，返回反转后的字符串。

    Args:
        input_string: 要反转的字符串。

    Returns:
        dict: 包含反转结果的字典。成功时返回 {'result': 反转后的字符串}，失败时返回 {'error': 错误信息}。
    """
    try:
        if not isinstance(input_string, str):
            return {'error': '输入必须是字符串类型'}
        reversed_str = input_string[::-1]
        return {'result': reversed_str}
    except Exception as e:
        return {'error': str(e)}

